1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  Pressable,
4	  SafeAreaView,
5	  ScrollView,
6	  StyleSheet,
7	  Text,
8	  View,
9	  type StyleProp,
10	  type ViewStyle,
11	} from 'react-native';
12	import { router } from 'expo-router';
13	import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
14	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
15	import { colors, radii, shadows, spacing } from '@/design/tokens';
16	import { textStyles } from '@/design/typography';
17	import { useAuth } from '@/lib/auth';
18	import { supabase } from '@/lib/supabase';
19	import { formatRelativeTime } from '@/lib/time';
20	import type { Database } from '@/types/supabase';
21	
22	// US-043 — Creator "My Applications" tab. Queries applications joined to
23	// listings + listing_versions (for the snapshot title) + users (for the
24	// lister handle) under the creator's JWT and groups rows into four
25	// segments: Pending / Approved / Rejected / Cancelled. Tap row →
26	// campaign detail. Spec: docs/design.md §3.1 (tab label "Applied") +
27	// product-plan §3 + §6 (statuses). Route path matches docs/design.md:151
28	// canonical URL `/(creator)/applications` (overrides the PRD's
29	// `applied.tsx` filename — existing TabBar wiring from US-031 wins).
30	
31	type ApplicationStatus = Database['public']['Enums']['application_status'];
32	type Segment = 'pending' | 'approved' | 'rejected' | 'cancelled';
33	
34	// Map the 6 DB enum values to 4 display buckets. `withdrawn` is a
35	// creator-initiated cancellation; both listing-* variants are
36	// lister-initiated. All three share the Cancelled segment per AC.
37	const STATUS_BUCKET: Record<ApplicationStatus, Segment> = {
38	  pending: 'pending',
39	  approved: 'approved',
40	  rejected: 'rejected',
41	  withdrawn: 'cancelled',
42	  cancelled_listing_edit: 'cancelled',
43	  cancelled_listing_closed: 'cancelled',
44	};
45	
46	const SEGMENTS: readonly { key: Segment; label: string }[] = [
47	  { key: 'pending', label: 'Pending' },
48	  { key: 'approved', label: 'Approved' },
49	  { key: 'rejected', label: 'Rejected' },
50	  { key: 'cancelled', label: 'Cancelled' },
51	];
52	
53	// Segmented control semantics: a11y role "tab" with single-select state.
54	// Chip primitive (checkbox role) is for multi-select filter rows — a
55	// segmented control needs single-select. Keeping this inline rather than
56	// promoting to a shared primitive until another screen needs it.
57	type SegmentControlProps = {
58	  active: Segment;
59	  onChange: (next: Segment) => void;
60	};
61	
62	function SegmentControl({ active, onChange }: SegmentControlProps) {
63	  return (
64	    <View style={styles.segmentRow} accessibilityRole="tablist">
65	      {SEGMENTS.map((s) => (
66	        <SegmentButton
67	          key={s.key}
68	          label={s.label}
69	          selected={active === s.key}
70	          onPress={() => onChange(s.key)}
71	          testID={`segment-${s.key}`}
72	        />
73	      ))}
74	    </View>
75	  );
76	}
77	
78	type SegmentButtonProps = {
79	  label: string;
80	  selected: boolean;
81	  onPress: () => void;
82	  testID?: string;
83	};
84	
85	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
86	  const bg = selected ? colors.primarySoft : colors.surface;
87	  const textColor = selected ? colors.primaryDeep : colors.ink;
88	  return (
89	    <Pressable
90	      onPress={onPress}
91	      accessibilityRole="tab"
92	      accessibilityState={{ selected }}
93	      accessibilityLabel={label}
94	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
95	      testID={testID}
96	    >
97	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
98	        {label}
99	      </Text>
100	    </Pressable>
101	  );
102	}
103	
104	// Row shape for the list query — title is inside `listing_versions.snapshot`,
105	// lister handle is `users.username` via `listings.lister_id`. We hand-roll
106	// the type instead of relying on embed inference so the component stays
107	// readable.
108	type SnapshotShape = { title?: string };
109	
110	type ApplicationRow = {
111	  id: string;
112	  status: ApplicationStatus;
113	  created_at: string;
114	  listing_id: string;
115	  listing: {
116	    id: string;
117	    lister_id: string;
118	    lister: { username: string } | null;
119	  } | null;
120	  version: {
121	    snapshot: SnapshotShape | null;
122	  } | null;
123	};
124	
125	export default function Applications() {
126	  const { user } = useAuth();
127	  const userId = user?.id ?? null;
128	
129	  const [segment, setSegment] = useState<Segment>('pending');
130	  const [rows, setRows] = useState<ApplicationRow[]>([]);
131	  const [loading, setLoading] = useState(true);
132	  const [error, setError] = useState<string | null>(null);
133	
134	  const load = useCallback(async () => {
135	    if (!userId) return;
136	    setLoading(true);
137	    setError(null);
138	    const { data, error: fetchError } = await supabase
139	      .from('applications')
140	      .select(
141	        `
142	        id,
143	        status,
144	        created_at,
145	        listing_id,
146	        listing:listings!listing_id (
147	          id,
148	          lister_id,
149	          lister:users!lister_id ( username )
150	        ),
151	        version:listing_versions!listing_version_id (
152	          snapshot
153	        )
154	        `,
155	      )
156	      .eq('creator_id', userId)
157	      .order('created_at', { ascending: false })
158	      .returns<ApplicationRow[]>();
159	
160	    if (fetchError) {
161	      setError("Couldn't load applications.");
162	      setRows([]);
163	    } else {
164	      setRows(data ?? []);
165	    }
166	    setLoading(false);
167	  }, [userId]);
168	
169	  useEffect(() => {
170	    void load();
171	  }, [load]);
172	
173	  const byBucket = useMemo(() => {
174	    const map: Record<Segment, ApplicationRow[]> = {
175	      pending: [],
176	      approved: [],
177	      rejected: [],
178	      cancelled: [],
179	    };
180	    for (const r of rows) {
181	      map[STATUS_BUCKET[r.status]].push(r);
182	    }
183	    return map;
184	  }, [rows]);
185	
186	  const visible = byBucket[segment];
187	
188	  return (
189	    <SafeAreaView style={styles.root}>
190	      <ScrollView contentContainerStyle={styles.scroll}>
191	        <Text style={[textStyles.display, styles.header]}>Applied</Text>
192	        <SegmentControl active={segment} onChange={setSegment} />
193	
194	        {loading ? (
195	          <View style={styles.list} testID="applications-loading">
196	            <SkeletonCard />
197	            <SkeletonCard />
198	          </View>
199	        ) : error ? (
200	          <View style={styles.emptyBox}>
201	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
202	          </View>
203	        ) : visible.length === 0 ? (
204	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
205	            <Text style={[textStyles.body, { color: colors.ink70 }]}>
206	              {emptyMessageFor(segment)}
207	            </Text>
208	          </View>
209	        ) : (
210	          <View style={styles.list}>
211	            {visible.map((row) => (
212	              <ApplicationRowCard key={row.id} row={row} />
213	            ))}
214	          </View>
215	        )}
216	      </ScrollView>
217	    </SafeAreaView>
218	  );
219	}
220	
221	function emptyMessageFor(segment: Segment): string {
222	  switch (segment) {
223	    case 'pending':
224	      return 'No pending applications yet. Apply from Discover.';
225	    case 'approved':
226	      return 'Nothing approved yet — keep applying.';
227	    case 'rejected':
228	      return 'No rejections here.';
229	    case 'cancelled':
230	      return 'No cancelled applications.';
231	  }
232	}
233	
234	type ApplicationRowCardProps = {
235	  row: ApplicationRow;
236	  style?: StyleProp<ViewStyle>;
237	};
238	
239	function ApplicationRowCard({ row, style }: ApplicationRowCardProps) {
240	  const title = row.version?.snapshot?.title ?? 'Untitled campaign';
241	  const handle = row.listing?.lister?.username ?? null;
242	  const pillStatus: StatusPillStatus = STATUS_BUCKET[row.status];
243	  const relative = formatRelativeTime(new Date(row.created_at));
244	
245	  const onPress = useCallback(() => {
246	    router.push(`/(creator)/listing/${row.listing_id}`);
247	  }, [row.listing_id]);
248	
249	  return (
250	    <Pressable
251	      onPress={onPress}
252	      accessibilityRole="button"
253	      accessibilityLabel={`${title}${handle ? ` by @${handle}` : ''}, ${pillStatus}, applied ${relative}`}
254	      style={[styles.card, shadows.hard, style]}
255	      testID={`application-${row.id}`}
256	    >
257	      <View style={styles.cardTopRow}>
258	        <View style={styles.cardTitleBlock}>
259	          <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={2}>
260	            {title}
261	          </Text>
262	          {handle ? (
263	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>@{handle}</Text>
264	          ) : null}
265	        </View>
266	        <StatusPill status={pillStatus} />
267	      </View>
268	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
269	    </Pressable>
270	  );
271	}
272	
273	const styles = StyleSheet.create({
274	  root: { flex: 1, backgroundColor: colors.canvas },
275	  scroll: {
276	    padding: spacing.base,
277	    gap: spacing.md,
278	    paddingBottom: spacing.xxxl,
279	  },
280	  header: {
281	    color: colors.ink,
282	    marginBottom: spacing.xs,
283	  },
284	  segmentRow: {
285	    flexDirection: 'row',
286	    flexWrap: 'wrap',
287	    gap: spacing.sm,
288	    marginBottom: spacing.xs,
289	  },
290	  segment: {
291	    minHeight: 32,
292	    paddingHorizontal: spacing.md,
293	    paddingVertical: spacing.xs + 2,
294	    borderRadius: radii.pill,
295	    borderWidth: 2,
296	    borderColor: colors.ink,
297	    alignItems: 'center',
298	    justifyContent: 'center',
299	  },
300	  list: {
301	    gap: spacing.md,
302	  },
303	  card: {
304	    backgroundColor: colors.surface,
305	    borderColor: colors.ink,
306	    borderWidth: 2,
307	    borderRadius: radii.card,
308	    padding: spacing.base,
309	    gap: spacing.sm,
310	  },
311	  cardTopRow: {
312	    flexDirection: 'row',
313	    gap: spacing.sm,
314	    alignItems: 'flex-start',
315	  },
316	  cardTitleBlock: {
317	    flex: 1,
318	    gap: spacing.xs,
319	  },
320	  emptyBox: {
321	    padding: spacing.lg,
322	    alignItems: 'center',
323	  },
324	});
